<script setup lang="ts">
import { computed, ref } from 'vue'

defineProps<{ embedded?: boolean }>()

const versions = [
  { version: 'KG-2026.07.12.008', status: '当前线上', entities: '+1,183.6 万', relations: '+2,040 万', properties: '+3,264 万', schema: 'v1.8', task: 'KG-FULL-20260712-008', publishedAt: '2026-07-12 18:42', publisher: '张建图', note: '人才、论文、企业和专利增量构建通过全部质量校验' },
  { version: 'KG-2026.07.11.007', status: '稳定历史', entities: '+842.6 万', relations: '+1,286 万', properties: '+1,908 万', schema: 'v1.8', task: 'KG-INC-20260711-021', publishedAt: '2026-07-11 18:30', publisher: '张建图', note: '企业产品和产业链关系增量更新' },
  { version: 'KG-2026.07.10.006', status: '稳定历史', entities: '+615.2 万', relations: '+964 万', properties: '+1,426 万', schema: 'v1.7', task: 'KG-INC-20260710-016', publishedAt: '2026-07-10 20:06', publisher: '张建图', note: '论文、项目和专利成果增量更新' },
]

const selectedVersion = ref<(typeof versions)[number] | null>(null)
const rollbackVersion = ref<(typeof versions)[number] | null>(null)
const rollbackReason = ref('线上数据校验发现异常，需要恢复到该稳定版本')
const actionMessage = ref('')
const current = computed(() => versions[0])

const submitRollback = () => {
  if (!rollbackVersion.value) return
  actionMessage.value = `已提交回退至 ${rollbackVersion.value.version} 的申请。系统将先检查 Schema 兼容性、影响范围和恢复快照，审批通过后再原子切换线上版本。`
  rollbackVersion.value = null
}
</script>

<template>
  <div :class="['version-page', { 'is-embedded': embedded }]">
    <header v-if="!embedded" class="version-head"><div><RouterLink to="/overview">← 返回平台总览</RouterLink><h1>图谱版本管理</h1><p>按构建批次发布不可变版本；线上查询始终指向一个已校验的稳定版本。</p></div><span><i />当前线上运行稳定</span></header>

    <p v-if="actionMessage" class="version-message">{{ actionMessage }}</p>

    <section class="version-list">
      <header><div><h2>版本记录</h2><p>保留发布内容、Schema、来源任务和操作人员，支持审计与回退。</p></div><span>共 {{ versions.length }} 个稳定版本</span></header>
      <table><thead><tr><th>图谱版本</th><th>状态</th><th>实体变化</th><th>关系变化</th><th>属性变化</th><th>Schema</th><th>来源任务</th><th>发布时间</th><th>发布人</th><th>操作</th></tr></thead><tbody><tr v-for="row in versions" :key="row.version"><td><strong>{{ row.version }}</strong><small>{{ row.note }}</small></td><td><em :class="row.status === '当前线上' ? 'is-current' : ''">{{ row.status }}</em></td><td>{{ row.entities }}</td><td>{{ row.relations }}</td><td>{{ row.properties }}</td><td>{{ row.schema }}</td><td><RouterLink :to="`/task-detail/construction/${row.task}?step=persist`">{{ row.task }}</RouterLink></td><td>{{ row.publishedAt }}</td><td>{{ row.publisher }}</td><td><div class="version-actions"><button type="button" @click="selectedVersion=row">变更详情</button><button v-if="row.status !== '当前线上'" class="danger" type="button" @click="rollbackVersion=row">申请回退</button></div></td></tr></tbody></table>
    </section>

    <button v-if="selectedVersion || rollbackVersion" class="version-mask" type="button" aria-label="关闭" @click="selectedVersion=null;rollbackVersion=null" />
    <aside v-if="selectedVersion" class="version-drawer"><header><div><span>图谱版本变更详情</span><h2>{{ selectedVersion.version }}</h2><p>{{ selectedVersion.publishedAt }} · {{ selectedVersion.publisher }}</p></div><button type="button" @click="selectedVersion=null">×</button></header><div><section><h3>本次变更</h3><dl><div><dt>实体变化</dt><dd>{{ selectedVersion.entities }}</dd></div><div><dt>关系变化</dt><dd>{{ selectedVersion.relations }}</dd></div><div><dt>属性变化</dt><dd>{{ selectedVersion.properties }}</dd></div><div><dt>Schema</dt><dd>{{ selectedVersion.schema }}</dd></div></dl></section><section><h3>发布说明</h3><p>{{ selectedVersion.note }}</p></section><section><h3>可恢复依据</h3><p>保留构建输入快照、候选层结果、质量报告和发布前线上版本指针，可用于影响分析和原子回退。</p></section></div></aside>

    <aside v-if="rollbackVersion" class="rollback-dialog"><header><h2>申请回退图谱版本</h2><button type="button" @click="rollbackVersion=null">×</button></header><p>将线上图谱从 {{ current.version }} 切换回 <strong>{{ rollbackVersion.version }}</strong>。提交后不会立即覆盖数据，必须先完成兼容性和影响检查。</p><label><span>回退原因</span><textarea v-model="rollbackReason" /></label><footer><button type="button" @click="rollbackVersion=null">取消</button><button class="danger" type="button" @click="submitRollback">提交回退申请</button></footer></aside>
  </div>
</template>

